import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the buffer size to prevent buffer overflow
        int bufferSize = Math.min(name.length(), 10);
        char[] buffer = new char[bufferSize];

        // Copying characters from user input to buffer with boundary check
        for (int i = 0; i < bufferSize; i++) {
            if (name.charAt(i) > 127) {
                System.out.println("Invalid character detected. Exiting.");
                return;
            }
            buffer[i] = name.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
